// src/pages/LabourDashboard.jsx

import { useEffect, useState } from "react";
import axios from "axios";
import Navbar from "../components/Navbar";

export default function LabourDashboard() {

  const user = JSON.parse(
    localStorage.getItem("user")
  );

  const [requests, setRequests] =
    useState([]);

  const [price, setPrice] =
    useState({});

  useEffect(() => {

    getRequests();

  }, []);

  const getRequests = async () => {

    const res = await axios.get(

      `http://localhost:5000/api/request/labour/${user._id}`

    );

    setRequests(res.data);
  };

  const respondRequest =
    async (id, action) => {

      await axios.put(

        `http://localhost:5000/api/request/labour-response/${id}`,

        {
          price: price[id] || 0,
          action
        }

      );

      getRequests();
    };

  return (

    <div style={styles.page}>

      <Navbar />

      <div style={styles.container}>

        <div style={styles.card}>

          <h2 style={styles.heading}>
            Request Received
          </h2>

          {requests.map((req) => (

            <div
              key={req._id}
              style={styles.requestBox}
            >

              {/* TOP ROW */}

              <div style={styles.topRow}>

                <h3 style={styles.name}>
                  {req.customerName}
                </h3>

                <span style={styles.status}>
                  {req.status}
                </span>

              </div>

              {/* DETAILS */}

              <div style={styles.details}>

                <p>
                  <b>Work:</b>
                  {" "}
                  {req.workType}
                </p>

                <p>
                  <b>Location:</b>
                  {" "}
                  {req.location}
                </p>

                <p>
                  <b>Date:</b>
                  {" "}
                  {req.date}
                </p>

                <p>
                  <b>Customer Decision:</b>
                  {" "}
                  {req.customerDecision}
                </p>

              </div>

              {/* PRICE INPUT */}

              <input
                type="number"
                placeholder="Enter Price"
                style={styles.input}
                onChange={(e) =>
                  setPrice({
                    ...price,
                    [req._id]:
                      e.target.value
                  })
                }
              />

              {/* BUTTONS */}

              {req.status ===
                "Pending" && (

                <div
                  style={styles.btnRow}
                >

                  <button
                    style={
                      styles.acceptBtn
                    }

                    onClick={() =>
                      respondRequest(
                        req._id,
                        "Accepted"
                      )
                    }
                  >
                    Accept
                  </button>

                  <button
                    style={
                      styles.rejectBtn
                    }

                    onClick={() =>
                      respondRequest(
                        req._id,
                        "Rejected"
                      )
                    }
                  >
                    Reject
                  </button>

                </div>

              )}

              {/* FEEDBACK */}

              {req.feedback && (

                <div
                  style={styles.feedbackBox}
                >

                  <div style={styles.starRow}>

                    {[1, 2, 3, 4, 5].map(
                      (star) => (

                      <span
                        key={star}
                        style={{

                          fontSize: "20px",

                          color:
                            req.feedback.rating >= star
                              ? "#facc15"
                              : "#d1d5db"

                        }}
                      >

                        ★

                      </span>

                    ))}

                  </div>

                  <p style={styles.comment}>

                    {req.feedback.comment}

                  </p>

                </div>

              )}

            </div>

          ))}

        </div>

      </div>

    </div>
  );
}

/* ================= ONLY UI CHANGED ================= */

const styles = {

  page: {
    background: "#f4f7fb",
    minHeight: "100vh"
  },

  container: {
    padding: "30px",
    maxWidth: "900px",
    margin: "auto"
  },

  card: {
    background: "white",
    padding: "25px",
    borderRadius: "18px",
    boxShadow:
      "0 4px 15px rgba(0,0,0,0.05)"
  },

  heading: {
    marginBottom: "24px",
    color: "#111827",
    textAlign: "center",
    fontSize: "24px"
  },

  requestBox: {
    border:
      "1px solid #e5e7eb",
    borderRadius: "16px",
    padding: "18px",
    marginBottom: "20px",
    background: "#ffffff",
    boxShadow:
      "0 2px 10px rgba(0,0,0,0.03)"
  },

  topRow: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    marginBottom: "14px"
  },

  name: {
    margin: 0,
    color: "#111827",
    fontSize: "18px"
  },

  status: {
    background: "#eff6ff",
    color: "#2563eb",
    padding: "6px 12px",
    borderRadius: "20px",
    fontSize: "12px",
    fontWeight: "bold"
  },

  details: {
    display: "flex",
    flexDirection: "column",
    gap: "8px",
    marginBottom: "16px",
    color: "#374151",
    fontSize: "14px"
  },

  input: {
    width: "100%",
    padding: "13px",
    borderRadius: "10px",
    border:
      "1px solid #d1d5db",
    outline: "none",
    boxSizing: "border-box",
    marginBottom: "14px",
    fontSize: "14px",
    background: "#f9fafb"
  },

  btnRow: {
    display: "flex",
    gap: "12px"
  },

  acceptBtn: {
    flex: 1,
    padding: "12px",
    background: "#16a34a",
    color: "white",
    border: "none",
    borderRadius: "10px",
    cursor: "pointer",
    fontWeight: "bold",
    fontSize: "14px"
  },

  rejectBtn: {
    flex: 1,
    padding: "12px",
    background: "#dc2626",
    color: "white",
    border: "none",
    borderRadius: "10px",
    cursor: "pointer",
    fontWeight: "bold",
    fontSize: "14px"
  },

  feedbackBox: {
    marginTop: "16px",
    background: "#f9fafb",
    padding: "14px",
    borderRadius: "10px"
  },

  starRow: {
    display: "flex",
    gap: "4px",
    marginBottom: "8px"
  },

  comment: {
    margin: 0,
    color: "#374151",
    fontSize: "14px"
  }

};
